#include <bits/stdc++.h>
using namespace std;
#define dbg(x) cerr<<#x" = "<<(x)<<endl;
#define ll long long
const int N=205;
int n,m,k,a[N][N],b[N][N],c[N][N][2];
bool flag[N][N];
int main()
{
	ios::sync_with_stdio(0);
	cin.tie(0),cout.tie(0);
//	freopen(".in","r",stdin);
//	freopen(".out","w",stdout);
	cin>>n>>m>>k;
	for(int i=1;i<=n;i++)
	{
		for(int j=1;j<=m;j++)
		{
			string s;
			cin>>a[i][j]>>s;
			if(s=="Y") flag[i][j]=1;
		}
	}
	for(int i=1;i<=m;i++)
	{
		int cnt=0;
		for(int j=n;j>0;j--)
		{
			if(flag[j][i]) b[i][cnt]+=a[j][i];
			else
			{
				cnt++;
				b[i][cnt]=b[i][cnt-1]+a[j][i];
			}
		}
	}
	for(int i=1;i<=m;i++)
	{
		for(int j=0;j<=k;j++)
		{
			for(int jj=0;jj<=min(n,j);jj++)
			{
				c[i][j][1]=max(c[i][j][1],c[i-1][j-jj][1]+b[i][jj]);
				if(jj)
				{
					c[i][j][0]=max(c[i][j][0],c[i-1][j-jj][1]+b[i][jj]);
				}
				if(j!=jj)
				{
					c[i][j][0]=max(c[i][j][0],c[i-1][j-jj][0]+b[i][jj]);
				}
			}
		}
	}
	cout<<c[m][k][0];
	return 0;
}
